const j = $json;
const q = String(j.user_question || '').toLowerCase().trim();

const incidentWords = [
  'site down','sites down','down site','down sites','how many site down','how many sites down',
  'power alarm','power alarms','tx alarm','tx alarms','transport','microwave','mpls tunnel',
  'vip down','root cause','cascaded','active alarms','site status','analyze site',
  'incident for site','incident analysis','full incident','analyze incident','incident details',
  'dashboard','summary card','executive summary','موقع واقع','مواقع واقعة','باور','داون',
  'aging','parked','warning','critical'
];

const isGreeting = ['hi','hello','hey','thanks','thank you','مرحبا','شكرا','شكراً','ازيك']
  .some(x => q === x || q.startsWith(x + ' '));

const hasIncident = incidentWords.some(x => q.includes(x));
const hasSiteLike = /[A-Z]{2,}\d{2,}/i.test(j.sitecode || q);

const modeMap = {
  site_down_count:'incident',
  site_down_list:'incident',
  power_alarm_summary:'incident',
  tx_alarm_summary:'incident',
  vip_down_sites:'incident',
  site_active_alarms:'incident',
  site_incident_summary:'incident',
  down_aging_summary:'incident',
  power_aging_summary:'incident',
  down_parked_summary:'incident',
  power_parked_summary:'incident',
  placeholder_request:'placeholder',
  free_chat:'free_chat'
};

j.intent = String(j.intent || '').toLowerCase().trim();
j.category = String(j.category || '').toUpperCase().trim();

if (modeMap[j.intent]) j.mode = modeMap[j.intent];

function forcePowerAging() {
  j.intent = 'power_aging_summary';
  j.category = 'POWER';
}
function forcePowerParked() {
  j.intent = 'power_parked_summary';
  j.category = 'POWER';
}
function forceDownAging() {
  j.intent = 'down_aging_summary';
  j.category = 'SITE_DOWN';
  j.sitedownflag = 'Yes';
}
function forceDownParked() {
  j.intent = 'down_parked_summary';
  j.category = 'SITE_DOWN';
  j.sitedownflag = 'Yes';
}

// HARD OVERRIDE from question first
if (q.includes('power') && q.includes('aging')) forcePowerAging();
if (q.includes('power') && q.includes('parked')) forcePowerParked();
if ((q.includes('warning') || q.includes('critical')) && q.includes('power')) forcePowerAging();
if ((q.includes('warning') || q.includes('critical')) && (q.includes('down') || q.includes('site'))) forceDownAging();

if (!j.intent || j.intent === 'unknown') {
  if (hasIncident) {
    j.mode = 'incident';

    if ((q.includes('full incident') || q.includes('incident analysis') || q.includes('analyze incident') || q.includes('incident details')) && !hasSiteLike) {
      j.mode = 'placeholder';
      j.intent = 'placeholder_request';
      j.request_profile = 'placeholder';
      j.requested_blocks = 'need_site_for_incident';
    } else if (q.includes('power') && q.includes('aging')) {
      forcePowerAging();
    } else if (q.includes('power') && q.includes('parked')) {
      forcePowerParked();
    } else if ((q.includes('warning') || q.includes('critical')) && q.includes('power')) {
      forcePowerAging();
    } else if (q.includes('aging') && (q.includes('down') || q.includes('site'))) {
      forceDownAging();
    } else if (q.includes('parked') && (q.includes('down') || q.includes('site'))) {
      forceDownParked();
    } else if ((q.includes('warning') || q.includes('critical')) && (q.includes('down') || q.includes('site'))) {
      forceDownAging();
    } else if (q.includes('power')) {
      j.intent = 'power_alarm_summary';
      j.category = 'POWER';
    } else if (q.includes('tx') || q.includes('transport') || q.includes('microwave') || q.includes('mpls')) {
      j.intent = 'tx_alarm_summary';
      j.category = 'TX';
    } else if (q.includes('vip')) {
      j.intent = 'vip_down_sites';
      j.category = 'SITE_DOWN';
      j.isvip = 'Yes';
      j.sitedownflag = 'Yes';
    } else if (hasSiteLike && (q.includes('analyze') || q.includes('status') || q.includes('incident') || q.includes('detail'))) {
      j.intent = 'site_incident_summary';
      j.request_profile = 'site_incident_summary';
    } else if (hasSiteLike && q.includes('active alarms')) {
      j.intent = 'site_active_alarms';
    } else if (q.includes('how many') || q.includes('count') || q.includes('كم')) {
      j.intent = 'site_down_count';
      j.category = 'SITE_DOWN';
      j.count_only = true;
      j.sitedownflag = 'Yes';
    } else {
      j.intent = 'site_down_list';
      j.category = 'SITE_DOWN';
      j.sitedownflag = 'Yes';
    }
  } else if (isGreeting) {
    j.mode = 'free_chat';
    j.intent = 'free_chat';
    j.request_profile = 'free_chat';
  } else {
    j.mode = 'placeholder';
    j.intent = 'placeholder_request';
    j.request_profile = 'placeholder';
  }
}

// FINAL INTENT->CATEGORY CONSISTENCY
if (j.intent === 'power_alarm_summary') j.category = 'POWER';
if (j.intent === 'power_aging_summary') j.category = 'POWER';
if (j.intent === 'power_parked_summary') j.category = 'POWER';
if (j.intent === 'tx_alarm_summary') j.category = 'TX';

if (j.intent === 'site_down_count') { j.category = 'SITE_DOWN'; j.sitedownflag = 'Yes'; }
if (j.intent === 'site_down_list') { j.category = 'SITE_DOWN'; j.sitedownflag = 'Yes'; }
if (j.intent === 'vip_down_sites') { j.category = 'SITE_DOWN'; j.sitedownflag = 'Yes'; j.isvip = 'Yes'; }
if (j.intent === 'down_aging_summary') { j.category = 'SITE_DOWN'; j.sitedownflag = 'Yes'; }
if (j.intent === 'down_parked_summary') { j.category = 'SITE_DOWN'; j.sitedownflag = 'Yes'; }

// extra defensive rule
if (q.includes('power') && j.intent.includes('aging')) {
  j.intent = 'power_aging_summary';
  j.category = 'POWER';
}
if (q.includes('power') && j.intent.includes('parked')) {
  j.intent = 'power_parked_summary';
  j.category = 'POWER';
}

if (!j.request_profile) {
  if (j.intent === 'site_incident_summary') j.request_profile = 'site_incident_summary';
  else if (j.intent === 'free_chat' || j.mode === 'free_chat') j.request_profile = 'free_chat';
  else if (j.intent === 'placeholder_request' || j.mode === 'placeholder') j.request_profile = 'placeholder';
  else j.request_profile = 'simple_query';
}

if (j.request_profile === 'site_incident_summary') {
  j.mode = 'incident';
  j.analysis_scope = 'per_site';
  j.anchor_type = 'sitecode';
  j.geo_type = j.sitecode ? 'site' : (j.geo_type || 'none');
}

j.output_view = /(dashboard|summary card|executive summary|card view|show dashboard)/i.test(q)
  ? 'dashboard'
  : 'text';

if (!j.geo_type) j.geo_type = 'none';
if (j.geo_type === 'site' && !j.sitecode) j.geo_type = 'none';
if (j.geo_type === 'region' && !j.region_input) j.geo_type = 'none';
if (j.geo_type === 'office' && !j.office_input) j.geo_type = 'none';

return [{ json: j }];

const j = $json;
const q = String(j.user_question || '').toLowerCase().trim();
const regionRaw = String(j.region_input || '').toLowerCase().trim();
const geoMap = {'alex':'Alex','alexandria':'Alex','اسكندرية':'Alex','اسكندريه':'Alex','cairo':'Cairo','القاهرة':'Cairo','delta':'East Delta|West Delta','دلتا':'East Delta|West Delta','upper egypt':'North Upper|South Upper','الصعيد':'North Upper|South Upper','sinai':'Sinai','سينا':'Sinai','سيناء':'Sinai'};
const officeRaw = String(j.office_input || '').trim();
const knownOffices = ['ALEX1','ALEX2','ALEX3','ALEX4','AlexCore','Cairo','CairoCore','Downtown','Gesr El Suiz','Giza','Helwan','Mohandesen','OSS','Shorouk','Tagamo3','DOMYAT','DYARBNEAGM','FAKOUS','MANSURA','ZAGAZIK','DAMANHOUR','DELENGAT','KAFR ELSHEIKH','SHEBIN','TANTA','ASSIUT','BANISUIEF','DEIR MAWAS','FAYOUM','MENYA','Maghagha','ASWAN','Abu simple','EDFO','GERGA','LUXOR','QENA','SOHAG','ABO REDIES','ARISH','HURGHADA','ISMAILIA','MARSA ALAM','NUWIBA','RASCEDER','SHARM','SUEZ','ZAFRANA'];

let intent = String(j.intent || '').trim();
let category = String(j.category || '').trim().toUpperCase();

// v3.9 FIX: Guardrails consolidated in INT_Operational_Guardrails only
let location_resolved=''; 
let office_resolved='';
if (j.geo_type==='region') location_resolved = geoMap[regionRaw] || j.region_input || '';
else if (j.geo_type==='office') office_resolved = knownOffices.find(o => o.toLowerCase() === officeRaw.toLowerCase()) || officeRaw;

const realNow = new Date();
// v3.9 FIX: Reliable Cairo timezone using Intl.DateTimeFormat.formatToParts
const cairoParts = Object.fromEntries(
  new Intl.DateTimeFormat('en-CA', {
    timeZone: 'Africa/Cairo',
    year:'numeric', month:'2-digit', day:'2-digit',
    hour:'2-digit', minute:'2-digit', second:'2-digit', hour12:false
  }).formatToParts(realNow).filter(p => p.type !== 'literal').map(p => [p.type, p.value])
);
const cairoElapsedMs = (parseInt(cairoParts.hour)*3600 + parseInt(cairoParts.minute)*60 + parseInt(cairoParts.second)) * 1000;
let startUnix = realNow.getTime() - cairoElapsedMs;
let endUnix = startUnix + 86400000 - 1;
if (q.includes('last 7 day') || q.includes('last week')) { 
  startUnix = realNow.getTime()-604800000; 
  endUnix = realNow.getTime(); 
}

const agingIntents = ['down_aging_summary','power_aging_summary','down_parked_summary','power_parked_summary'];
const isAgingIntent = agingIntents.includes(intent);

// Safe fallback for aging/parked: last 3 months up to now
if (isAgingIntent) {
  startUnix = realNow.getTime() - (90 * 24 * 60 * 60 * 1000);
  endUnix = realNow.getTime();
}

const pad = n => String(n).padStart(2,'0');
const fmt = d => `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`;

return [{ json: {
  mode:j.mode, intent, category, request_profile:j.request_profile, analysis_scope:j.analysis_scope||'', anchor_type:j.anchor_type||'', requested_blocks:j.requested_blocks||'', user_question:j.user_question, debugMode:!!j.debugMode, _aiRaw:j._aiRaw||'', output_view:j.output_view || 'text',
  filters:{ vendor:j.vendor||'', technology:j.technology||j.networktype||'', severity: isAgingIntent ? '' : (j.severity||''), acknowledged:j.acknowledged||'', isvip:j.isvip||'', domain:j.domain||'', sitedownflag:(category==='SITE_DOWN' ? (j.sitedownflag||'Yes') : ''), sitepoweroff:j.sitepoweroff||'', sitecode:j.sitecode||'' },
  geography:{ geo_type:j.geo_type||'none', region_input:j.region_input||'', office_input:j.office_input||'', location_resolved, office_resolved },
  time_range:{ starttime:startUnix, endtime:endUnix, start_local: fmt(new Date(startUnix)), end_local: fmt(new Date(endUnix)) },
  count_only:!!j.count_only,
  isAgingIntent
}}];

const q = String($json.user_question || '').trim();
let reply = '👋 Hello! I am the NOC Operations AI Assistant. Try asking about site down, power alarms, TX alarms, or a specific site code.';
if (/thanks|thank you|شكرا|شكراً/i.test(q)) {
  reply = '😊 You are welcome. Ask me about down sites, power alarms, TX alarms, or a specific site code.';
}
const now = new Date().toISOString();
const debug = {
  '1_user_request': { question: q, debug_mode: false, timestamp: now, elapsed_label: 'V3.8 Foundation' },
  '2_ai_raw_output': { raw: '(free chat path)' },
  '3_ai_interpretation': { mode: 'free_chat', intent: 'free_chat', category: '', geo_type: 'none', technology: '', filters: {} },
  '4_geography': { region_input: '', office_input: '', geo_type: 'none', location_resolved: '', office_resolved: '' },
  '5_sql_mapping': { skipped: true, reason: 'free chat path' },
  '6_time_range': { skipped: true },
