  '8_api_response': { skipped: true },
  '9_post_filter_dedup': { skipped: true },
  '10_count_logic': { skipped: true },
  '11_final_reply': { preview: reply.slice(0, 200) }
};
return [{
  json: {
    version: 'v1',
    response_type: 'text',
    intent: 'free_chat',
    category: '',
    reply,
    total: 0,
    summary: {},
    charts: {},
    tables: {},
    filters: {},
    meta: { generated_at: now },
    debug,
    dashboard_data: null
  }
}];

const j = $json;
const q = String(j.user_question || '').toLowerCase();
const needsSite = (q.includes('full incident') || q.includes('incident analysis') || q.includes('analyze incident') || q.includes('incident details')) && !String(j.filters?.sitecode || '').trim();
let reply;
if (needsSite || j.requested_blocks === 'need_site_for_incident') {
  reply = 'Please provide the site code to continue incident full analysis. Example: Analyze site ALX3480';
} else {
  const mode = j.mode || 'placeholder';
  const intent = j.intent || 'placeholder_request';
  reply = `⚠️ ${mode} / ${intent} — Data source not connected yet.\n\nThis capability is part of the future plan.`;
}
const now = new Date().toISOString();
const debug = {
  '1_user_request': { question: j.user_question || '', debug_mode: !!j.debugMode, timestamp: now, elapsed_label: 'V3.8 Foundation' },
  '2_ai_raw_output': { raw: j._aiRaw || '(not captured)' },
  '3_ai_interpretation': { mode: j.mode || '', intent: j.intent || '', category: j.category || '', geo_type: j.geography?.geo_type || 'none', technology: j.filters?.technology || '', filters: j.filters || {} },
  '4_geography': { region_input: j.geography?.region_input || '', office_input: j.geography?.office_input || '', geo_type: j.geography?.geo_type || 'none', location_resolved: j.geography?.location_resolved || '', office_resolved: j.geography?.office_resolved || '' },
  '5_sql_mapping': { skipped: true, reason: 'placeholder path' },
  '6_time_range': { start_local: j.time_range?.start_local || '', end_local: j.time_range?.end_local || '', api_type: 0 },
  '7_api_payload': { skipped: true, reason: 'placeholder path' },
  '8_api_response': { skipped: true },
  '9_post_filter_dedup': { skipped: true },
  '10_count_logic': { skipped: true },
  '11_final_reply': { preview: reply.slice(0, 200) }
};
return [{
  json: {
    version: 'v1',
    response_type: 'text',
    intent: j.intent || 'placeholder_request',
    category: j.category || '',
    reply,
    total: 0,
    summary: {},
    charts: {},
    tables: {},
    filters: {},
    meta: { generated_at: now },
    debug,
    dashboard_data: null
  }
}];

const j=$json;
let intent = String(j.intent || '').trim();
let cat = String(j.category || '').toUpperCase().trim();
const q = String(j.user_question || '').toLowerCase().trim();

// v3.9 FIX: Trust guardrail output - intent/category already correct
const ven=(j.filters?.vendor||'').trim();
const tech=(j.filters?.technology||'').trim();
let sql="SELECT '__DIRECT__' AS alarm_name";

if(['SITE_DOWN','POWER','TX','CELL_DOWN'].includes(cat)){
  let where=[`category = '${cat.replace(/'/g,"''")}'`];
  if(ven) where.push(`vendor = '${ven.replace(/'/g,"''")}'`);
  if(tech) where.push(`technology = '${tech.replace(/'/g,"''")}'`);
  sql=`SELECT alarm_name FROM ai_alarm_mappings WHERE ${where.join(' AND ')} ORDER BY alarm_name;`;
}

if(j.request_profile==='site_incident_summary' || intent==='site_active_alarms') sql="SELECT '__DIRECT__' AS alarm_name";

return [{json:{...j, intent, category:cat, sql}}];

const t = $('ENGINE_Build SQL').item.json;
const sqlItems = $items('DB_Get Alarm Names');
const allNames = sqlItems.map(i => i.json.alarm_name).filter(Boolean);
const isDirectMode = allNames.length === 0 || allNames.includes('__DIRECT__');

const agingIntents = ['down_aging_summary','power_aging_summary','down_parked_summary','power_parked_summary'];
const isAgingIntent = agingIntents.includes(String(t.intent || '').trim());

let payload = {
  start: 0,
  limit: 1000,
  type: 1
};

function add(key, val) {
  if (val !== undefined && val !== null && String(val).trim() !== '') payload[key] = val;
}

// Aging / parked still need API mandatory time headers
// Use safe fallback = last 3 months prepared in CORE_Build Unified Context
add('starttime', t.time_range?.starttime);
add('endtime', t.time_range?.endtime);

// Primary query driver = mapping alarms only
if (!isDirectMode && allNames.length > 0) {
  add('alarmname', allNames.join('|'));
}

// Geography filters only when explicitly requested
if (t.geography.geo_type === 'region' && t.geography.location_resolved) add('location', t.geography.location_resolved);
else if (t.geography.geo_type === 'office' && t.geography.office_resolved) add('city', t.geography.office_resolved);
add('sitecode', t.filters.sitecode);

// Optional direct filters
add('vendor', t.filters.vendor);
add('networktype', t.filters.technology);
add('acknowledged', t.filters.acknowledged);
add('isvip', t.filters.isvip);
add('domain', t.filters.domain);

// Never send severity filters for aging / parked
if (!isAgingIntent) {
  const sev = String(t.filters.severity || '').toLowerCase().trim();
  const alevs = ['critical','major','minor','warning'];
  const clevs = ['uncleared','cleared','active','open'];
  if (alevs.includes(sev)) add('standardalarmseverity', sev.charAt(0).toUpperCase()+sev.slice(1));
  if (clevs.includes(sev)) add('severity', sev.charAt(0).toUpperCase()+sev.slice(1));
}

return [{ json: { ...t, api_payload: payload, mapping_alarm_names: allNames, isDirectMode, isAgingIntent } }];

const t = $('ENGINE_Build API Payload').item.json;
const pageInputs = $input.all();

// v3.9 FIX: Detect API calls that failed (returned no data)
const failedPageIndices = pageInputs.map((item, i) => ({ i, raw: item.json || {} })).filter(({ raw }) => !raw.result && !raw.data && !raw.records && !raw.rows && !raw.items).map(({ i }) => i);
const paginationWarning = failedPageIndices.length > 0 ? 'Data may be incomplete: ' + failedPageIndices.length + ' page(s) failed to return data.' : null;

function extractRecords(raw) {
  if (!raw || typeof raw !== 'object') return [];
  return Array.isArray(raw.result) ? raw.result
    : Array.isArray(raw.data) ? raw.data
    : Array.isArray(raw.records) ? raw.records
    : Array.isArray(raw.rows) ? raw.rows
    : Array.isArray(raw.items) ? raw.items
    : [];
}

let allRecords = [];
let pageSizes = [];
let pageMeta = [];
let apiTotals = [];

for (const item of pageInputs) {
  const raw = item.json || {};
  const recs = extractRecords(raw);
  const total = Number(raw.total || raw.count || raw.totalCount || raw.totalRecords || recs.length || 0);

  allRecords.push(...recs);
  pageSizes.push(recs.length);
  apiTotals.push(total);
  pageMeta.push({
    start: raw.api_payload?.start ?? raw._page?.start ?? null,
    limit: raw.api_payload?.limit ?? raw._page?.limit ?? null,
    page_index: raw._page?.index ?? null,
    records: recs.length,
    total
  });
}

const requestedPages = pageSizes.length;
const nonEmptyPages = pageSizes.filter(n => n > 0).length;
const firstShortPageIndex = pageSizes.findIndex(n => n < Number(t.api_payload?.limit || 1000));
const endedNaturally = firstShortPageIndex >= 0;
const reachedCap = !endedNaturally && requestedPages > 0 && pageSizes[requestedPages - 1] === Number(t.api_payload?.limit || 1000);
const apiRealTotal = Math.max(...apiTotals, allRecords.length, 0);

let records = allRecords;

/* ---------------------------
   SAFE POST-FILTERS
--------------------------- */
if (t.filters.vendor) {
  const v = String(t.filters.vendor).toLowerCase();
  records = records.filter(r => String(r.vendor || '').toLowerCase().includes(v));
}
if (t.filters.technology) {
  const tech = String(t.filters.technology).toLowerCase();
  records = records.filter(r => String(r.networktype || '').toLowerCase().includes(tech));
}
if (t.filters.acknowledged) {
  records = records.filter(r => String(r.acknowledged || '') === String(t.filters.acknowledged));
}
if (t.filters.sitecode) {
  const sc = String(t.filters.sitecode).trim().toUpperCase();
  records = records.filter(r => String(r.sitecode || '').trim().toUpperCase() === sc);
}
if (t.filters.isvip) {
  records = records.filter(r => String(r.isvip || '').toLowerCase() === 'yes');
}

/* IMPORTANT:
   Never filter aging/parked by API severity aliases such as Warning/Critical.
   Those are time-threshold concepts in this workflow, not standardalarmseverity filters.
*/
const logicalRecords = Array.isArray(records) ? records : [];

/* ---------------------------
   HELPERS
--------------------------- */
function parseAlarmTime(ts) {
  if (ts === undefined || ts === null || ts === '') return NaN;
  if (typeof ts === 'number') return ts;

  const s = String(ts).trim();
  if (/^\d{13}$/.test(s)) return Number(s);
  if (/^\d{10}$/.test(s)) return Number(s) * 1000;

  const parsed = new Date(s).getTime();
  return Number.isNaN(parsed) ? NaN : parsed;
}

function normalizeSiteKey(r) {
  const a = String(r.sitecode || '').trim().toUpperCase();
  const b = String(r.sitename || '').trim().toUpperCase();
  const invalid = new Set(['', '-', 'NULL', 'N/A', 'UNKNOWN', '0']);

  if (a && !invalid.has(a)) return a;
  if (b && !invalid.has(b)) return b;
  return '';
}

function normalizeAlarmName(r) {
  return String(r.alarmname || r.rawalarmname || '').trim();
}

function tallyBy(arr, getter) {
  const m = {};
  for (const r of arr) {
    const k = String(getter(r) || 'Unknown').trim() || 'Unknown';
    m[k] = (m[k] || 0) + 1;
  }
  return Object.entries(m)
    .sort((a, b) => b[1] - a[1])
    .map(([name, count]) => ({ name, count }));
}

function makeTopSites(arr) {
  const m = {};
  for (const r of arr) {
    const site = normalizeSiteKey(r);
    if (!site) continue;
    const office = String(r.city || '').trim();
    if (!m[site]) m[site] = { site, office, value: 0 };
    m[site].value += 1;
  }
  return Object.values(m).sort((a, b) => b.value - a.value).slice(0, 8);
}

function getLatestPerSite(rows) {
  const m = new Map();
  for (const r of rows) {
    const site = normalizeSiteKey(r);
    if (!site) continue;

    const currTs = parseAlarmTime(r.lastoccurrence || r.firstoccurrence || r.eventtime || r.time || '');
    const old = m.get(site);
    const oldTs = old ? parseAlarmTime(old.lastoccurrence || old.firstoccurrence || old.eventtime || old.time || '') : -1;

    if (!old || currTs > oldTs) {
      m.set(site, r);
    }
  }
  return Array.from(m.values());
}

function filterRowsByAge(rows, minHours) {
  const nowMs = Date.now();
  return rows.filter(r => {
    const tms = parseAlarmTime(r.lastoccurrence || r.firstoccurrence || r.eventtime || r.time || '');
    if (Number.isNaN(tms)) return false;
    return ((nowMs - tms) / 3600000) > minHours;
  });
}

function computeAging(rows) {
  const nowMs = Date.now();
  let lt2h = 0, h2_4 = 0, h4_12 = 0, gt12h = 0, warn_gt6 = 0, crit_gt12 = 0, parked_gt24 = 0;

  for (const r of rows) {
    const tms = parseAlarmTime(r.lastoccurrence || r.firstoccurrence || r.eventtime || r.time || '');
