    if (diffH < 2) lt2h++;
    else if (diffH < 4) h2_4++;
    else if (diffH < 12) h4_12++;
    else gt12h++;

    if (diffH > 6) warn_gt6++;
    if (diffH > 12) crit_gt12++;
    if (diffH > 24) parked_gt24++;
  }

  return {
    '<2h': lt2h,
    '2_4h': h2_4,
    '4_12h': h4_12,
    '>12h': gt12h,
    warning_gt_6h: warn_gt6,
    critical_gt_12h: crit_gt12,
    parked_gt_24h: parked_gt24
  };
