const isAging = agingIntents.includes(base.intent);

const limit = Number(base.api_payload?.limit || 1000);
const maxPages = isAging ? 25 : (isBroad ? 10 : 1);

const out = [];
for (let i = 0; i < maxPages; i++) {
  const cloned = JSON.parse(JSON.stringify(base));
  cloned.api_payload = cloned.api_payload || {};
  cloned.api_payload.start = i * limit;
  cloned.api_payload.limit = limit;
  cloned._page = {
    index: i,
    start: cloned.api_payload.start,
    limit,
    max_pages: maxPages,
    is_broad: isBroad,
    is_aging: isAging
  };
  out.push({ json: cloned });
}
return out;
